import{_ as d,o as e,c as r,ag as a}from"./chunks/framework.f_9xDHrT.js";const p=JSON.parse('{"title":"宇宙探索","description":"MissFisher 的宇宙探索任务说明。","frontmatter":{"title":"宇宙探索","description":"MissFisher 的宇宙探索任务说明。"},"headers":[],"relativePath":"manual/scenarios/cosmic.md","filePath":"manual/scenarios/cosmic.md","lastUpdated":null}'),s={name:"manual/scenarios/cosmic.md"};function l(i,t,n,c,I,o){return e(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="宇宙探索" tabindex="-1">宇宙探索 <a class="header-anchor" href="#宇宙探索" aria-label="Permalink to &quot;宇宙探索&quot;">​</a></h1><p>在使用捕鱼人接取宇宙探索任务后，MissFisher 会自动识别任务并启动对应预设。</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p></p><ul><li>建议安装的插件：ICE</li><li>ICE 可以自动刷取、接取和提交特定任务。</li><li>如果你还未安装，可以在 MissFisher 的设置页里找到 ICE 的仓库链接。</li></ul></div><p>满足各类需求效率较高的任务：</p><table tabindex="0"><thead><tr><th style="text-align:center;">探索地点</th><th>类别</th><th>探索任务名</th><th>说明</th></tr></thead><tbody><tr><td style="text-align:center;">憧憬湾</td><td>C 类</td><td>协助调查基地西北侧的水质</td><td>可以高效获取数据 I、数据 II，<br>也可以刷月面信用点</td></tr><tr><td style="text-align:center;">憧憬湾</td><td>A 类</td><td>检验钓场的多样性</td><td>可以高效获取数据 III、数据 IV，<br>也可以刷宇宙信用点和技巧点</td></tr><tr><td style="text-align:center;">憧憬湾</td><td>A 类</td><td>采集魔泉环境的样本</td><td>【限时】可以高效获取数据 III、数据 IV，<br>也可以刷宇宙信用点和技巧点</td></tr><tr><td style="text-align:center;">憧憬湾</td><td>A 类</td><td>【高难】制作改良版月凝胶</td><td>可以高效获取捕鱼人技巧点，<br>需要你的炼金术师职业有正常的等级、<br>技能和已部分禁忌镶嵌的新装备（对于7.4），<br>且需要使用生产职业用的食品</td></tr><tr><td style="text-align:center;">法恩娜</td><td>C 类</td><td>高效筹备水产食品</td><td>可以高效获取数据 I、数据 II、数据 III</td></tr><tr><td style="text-align:center;">法恩娜</td><td>A 类</td><td>支援利用水产资源开发精密镜片</td><td>可以高效获取数据 III、数据 IV、数据 V</td></tr><tr><td style="text-align:center;">法恩娜</td><td>A 类</td><td>【高难】大型水产资源的捕获调查</td><td>可以高效获取数据 II、数据 IV、数据 V</td></tr><tr><td style="text-align:center;">俄匊斯</td><td>B 类</td><td>调查养殖鱼的重力异常适应性</td><td>可以高效获取数据 II、数据 III、数据 IV</td></tr><tr><td style="text-align:center;">俄匊斯</td><td>A 类</td><td>调查海洋水产品的可食用性</td><td>可以高效获取数据 I、数据 V、数据 VI</td></tr></tbody></table>',5)])])}const _=d(s,[["render",l]]);export{p as __pageData,_ as default};
